  2→import os from "node:os";
  3→import path from "node:path";
  4→import { describe, it } from "node:test";
  5→import { AGENT_REGISTRY } from "../src/config/agents.ts";
  6→import {
  7→  resolveAgentDetectPath,
  8→  resolveAgentSkillPath,
  9→  resolveHome,
 10→} from "../src/core/resolve.ts";
 11→import { UserError } from "../src/errors.ts";
 12→
 13→function getAgent(id: string) {
 14→  const agent = AGENT_REGISTRY.find((a) => a.id === id);
 15→  assert.ok(agent, `agent "${id}" not found in AGENT_REGISTRY`);
 16→  return agent;
 17→}
 18→
 19→describe("resolveAgentSkillPath", () => {
 20→  it("resolves Claude Code skill path", () => {
 21→    const claude = getAgent("claude-code");
 22→    const result = resolveAgentSkillPath(claude, "my-skill", "/Users/test");
 23→    assert.equal(
 24→      result,
 25→      path.join("/Users/test", ".claude", "skills", "my-skill"),
 26→    );
 27→  });
 28→
 29→  it("resolves OpenCode skill path with home", () => {
 30→    const opencode = getAgent("opencode");
 31→    const result = resolveAgentSkillPath(opencode, "test-skill", "/home/user");
 32→    // On non-Windows the posix template is used; cross-platform template tests live in cross-platform.test.ts
 33→    assert.ok(result.includes("opencode") && result.includes("test-skill"));
 34→  });
 35→
 36→  it("resolves Antigravity nested path", () => {
 37→    const antigravity = getAgent("antigravity");
 38→    const result = resolveAgentSkillPath(antigravity, "my-skill", "/home/user");
 39→    assert.equal(
 40→      result,
 41→      path.join("/home/user", ".gemini", "antigravity", "skills", "my-skill"),
 42→    );
 43→  });
 44→});
 45→
 46→describe("resolveAgentDetectPath", () => {
 47→  it("resolves detect path for each agent", () => {
 48→    for (const agent of AGENT_REGISTRY) {
 49→      const result = resolveAgentDetectPath(agent, "/home/user");
 50→      assert.ok(
 51→        path.isAbsolute(result),
 52→        `expected absolute path, got: ${result}`,
